VALUES
  ('bookkeeper-moex-01362', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司發行面額$10之普通股，流通在外200,000股，另外亦發行面額$100，6%之累積特別股10,000股。 過去三年及今年皆未發放股利，若公司本年度欲宣告發放$150,000 之股利，則今年底分配給特別股之股 利是多少？', '["$150,000", "$240,000", "$360,000", "$480,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01363', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲、乙、丙三人之合夥商店，甲資本$20,000、乙資本$30,000、丙資本$40,000，損益分配比例為5：3：2。 經全體合夥人同意決定清算解散，合夥企業變產得款$200,000，其中清算利益$100,000，則丙合夥人可收 回現金：', '["$60,000", "$80,000", "$100,000", "$200,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01364', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司期初資產總額$800,000、期初負債總額$500,000、本期銷貨收入$1,210,000、銷貨退回$10,000、銷 貨成本$700,000、期末存貨$100,000、營業費用$300,000、利息支出$100,000，則期末結帳後的股東權益 為若干？', '["$100,000", "$200,000", "$300,000", "$400,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01365', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列有關零用金之敘述，何者正確？', '["平日零星支付時，應借記各項費用，貸記零用金", "設置時，應借記零用金，貸記現金", "採不定額預付制", "補充零用金時，應借記零用金，貸記現金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01366', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列有關銀行往來調節表中未兌現支票之敘述，何者正確？', '["需作補正分錄", "應列為銀行對帳單餘額之加項", "應列為銀行對帳單餘額之減項", "應列為公司帳面存款餘額之減項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01367', 'bookkeeper', 'bookkeeper-moex-103-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X3年1月1日發行三年期，票面利率10%，面額$400,000之公司債，於每年6月30日及 12月31日各付息一次，公司債發行價格為$435,000，有效利率為8%。該公司採有效利率法攤銷折、 溢價。則X3年之利息費用為：', '["$34,696", "$34,800", "$40,000", "$43,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "eb7c2b3095ad", "answer_pdf_sha1": "151da49cfd80", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01368', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列何者不是稅捐稽徵法的適用範圍？', '["營業稅", "關稅", "所得稅", "土地稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01369', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '大利光公司於103年5月5日辦理102年度營利事業所得稅結算申報，依現行稅捐稽徵法之規定，其核課期 間自何時算起？', '["103年5月1日", "103年5月5日", "103年5月6日", "103年6月1日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01370', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '在中華民國境內之營利事業，其已確定之應納稅捐逾法定繳納期限尚未繳納完畢，所欠繳稅款及已確定之罰 鍰單計或合計，在新臺幣多少元以上者；另其在行政救濟程序終結前，在新臺幣多少元以上，得由財政部 函請內政部入出國及移民署限制其負責人出境，但已提供相當擔保者，應解除其限制？', '["一百萬元，一百五十萬元", "一百五十萬元，三百萬元", "二百萬元，二百五十萬元", "二百萬元，三百萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01371', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法規定，若以黃金做為稅款之相當擔保品，則應按幾折計價？', '["七折", "八折", "九折", "無須折價計算"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01372', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法第27條規定，納稅義務人對核准延期或分期繳納之任何一期應繳稅捐，未如期繳納者，稅捐 稽徵機關應於該期繳納期間屆滿之翌日起三日內，就未繳清之餘額稅款，發單通知納稅義務人，且限幾日 內一次全部繳清？', '["八日", "十日", "十五日", "二十日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01373', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法第20條規定，逾期繳納稅捐應加徵滯納金者，每逾二日按滯納數額加徵百分之多少的滯納金？ 而逾幾日仍未繳納者，移送法院強制執行？', '["百分之一，30日", "百分之一，45日", "百分之二，30日", "百分之二，45日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01374', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法第60條規定，一般情況下營利事業之著作權，應按幾年為計算攤折之標準？', '["五年", "十年", "十五年", "無規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01375', 'bookkeeper', 'bookkeeper-moex-103-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法規定，綜合所得稅納稅義務人結算申報所列報之免稅及扣除項目或金額，超過規定之限制，致短 繳稅款，經稽徵機關核定補繳者，除補徵稅額外，亦應按日加計利息。而此一應加計之利息金額不超過多 少元者，免予加計徵收？', '["一千二百元", "一千五百元", "一千八百元", "二千元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "bb46751672cc", "answer_pdf_sha1": "7502bd95d11d", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
